import React, { useState } from "react";

function RecipeCreate( {onRecipeCreate }) {
  const [formData, setFormData] = useState({
    name: "", 
    cuisine: "", 
    photo: "", 
    ingredients: "", 
    preparation: ""
  });
  // TODO: When the form is submitted, a new recipe should be created, and the form contents cleared.
  // TODO: Add the required input and textarea form elements.
  // TODO: Add the required submit and change handlers.
  const handleChange = ({ target }) => {
    setFormData({ ...formData, [target.name]: target.value });
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    const newRecipe = { //values in the form
      name: event.target.elements.name.value,
      cuisine: event.target.elements.cuisine.value,
      photo: event.target.elements.photo.value,
      ingredients: event.target.elements.ingredients.value,
      preparation: event.target.elements.preparation.value,
    }

    console.log(event.target.elements.content.value);
    onRecipeCreate(newRecipe);
    event.target.reset();
  }


  return (
    <form name="create" onSubmit={handleSubmit}>
      <table>
        <tbody>
          <tr>
            <td>
              <label htmlFor="name"></label>
              <textarea
                id="name"
                name="name"
                placeholder="Name"
                onChange={handleChange}
                required={true}
                rows={1} />
            </td>
            <td>
              <label htmlFor="cuisine"></label>
              <textarea
                id="cuisine"
                name="cuisine"
                placeholder="Cuisine"
                onChange={handleChange}
                required={true}
                rows={1} />
            </td>
            <td>
              <label htmlFor="photo"></label>
              <input
                id="photo"
                name="photo"
                placeholder="URL"
                type="url"
                required={true} />
            </td>
            <td>
              <label htmlFor="ingredients"></label>
              <textarea
                id="ingredients"
                name="ingredients"
                placeholder="Ingredients"
                onChange={handleChange}
                required={true}
                rows={3} />
            </td>
            <td>
              <label htmlFor="preparation"></label>
              <textarea
                id="preparation"
                name="preparation"
                placeholder="Preparation"
                onChange={handleChange}
                required={true}
                rows={3} />
            </td>
            <td>
              <button type="submit">Create</button>
            </td>
          </tr>
        </tbody>
      </table>
    </form>
  );
}

export default RecipeCreate;
